from flask import Flask, request, session, jsonify
from redis import Redis
import pickle
import hashlib
import time
import functools
import os

app = Flask(__name__)
app.secret_key = os.environ.get('SECRET_KEY', 'your-secret-key-here')

# Redis connection
redis_client = Redis(host='localhost', port=6379, db=0, decode_responses=False)

def cache_result(expiration=300):
    def decorator(func):
        @functools.wraps(func)
        def wrapper(*args, **kwargs):
            # Create cache key
            cache_key = f"cache:{func.__name__}:{hashlib.md5(str(args + tuple(sorted(kwargs.items()))).encode()).hexdigest()}"
            
            # Try to get from cache
            cached_result = redis_client.get(cache_key)
            if cached_result:
                return pickle.loads(cached_result)
            
            # Execute function and cache result
            result = func(*args, **kwargs)
            redis_client.setex(cache_key, expiration, pickle.dumps(result))
            return result
        return wrapper
    return decorator

@app.before_request
def load_session():
    if 'session_id' in request.cookies:
        session_id = request.cookies['session_id']
        session_data = redis_client.get(session_id)
        if session_data:
            session.update(pickle.loads(session_data))

@app.after_request
def save_session(response):
    if session:
        session_id = request.cookies.get('session_id', hashlib.md5(str(time.time()).encode()).hexdigest())
        redis_client.setex(session_id, 3600, pickle.dumps(dict(session)))
        response.set_cookie('session_id', session_id, httponly=True, secure=True, samesite='Lax')
    return response

@app.route('/login', methods=['POST'])
def login():
    username = request.json.get('username')
    password = request.json.get('password')
    
    # Validate credentials (mock implementation)
    if username and password:
        session['username'] = username
        session['authenticated'] = True
        return jsonify({'status': 'success'})
    
    return jsonify({'status': 'error', 'message': 'Invalid credentials'}), 401

@app.route('/logout', methods=['POST'])
def logout():
    session.clear()
    response = jsonify({'status': 'success'})
    response.set_cookie('session_id', '', expires=0)
    return response

@cache_result(expiration=600)
def expensive_database_query(user_id):
    # Simulate expensive database operation
    time.sleep(2)
    return {'user_id': user_id, 'data': f'Expensive data for user {user_id}'}

@app.route('/user/<int:user_id>')
def get_user_data(user_id):
    if not session.get('authenticated'):
        return jsonify({'error': 'Unauthorized'}), 401
    
    data = expensive_database_query(user_id)
    return jsonify(data)

